import "./EmployeeDetails.css";
import { useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { isAdmin, isEmployee, getLoggedInUser } from "../auth";

function EmployeeDetails() {

  const navigate = useNavigate();

  /* ---------------- BASE PATH FIX ---------------- */
  const user = getLoggedInUser();
  const role = user?.role?.toUpperCase();

  const base =
    role === "ADMIN"
      ? "/admin-dashboard"
      : "/employee-dashboard";

  /* ---------------- STATE ---------------- */
  const [employees, setEmployees] = useState([]);
  const [searchEmpId, setSearchEmpId] = useState("");

  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || null;

  /* ---------------- LOAD EMPLOYEES ---------------- */
  useEffect(() => {
    const stored =
      JSON.parse(localStorage.getItem("employees")) || [];
    setEmployees(stored);
  }, []);

  /* ---------------- EMPLOYEE SELF VIEW ---------------- */
  let roleFilteredEmployees = employees;

  if (isEmployee()) {
    const match = employees.find((emp) =>
      String(emp?.empId) === String(loggedUser?.empId) ||
      String(emp?.id) === String(loggedUser?.empId) ||
      String(emp?.email) === String(loggedUser?.username) ||
      String(emp?.name)?.toLowerCase() ===
        String(loggedUser?.name)?.toLowerCase()
    );

    roleFilteredEmployees = match ? [match] : [];
  }

  /* ---------------- ADMIN SEARCH ---------------- */
  const filteredEmployees = isAdmin()
    ? roleFilteredEmployees.filter((emp) =>
        emp.empId
          ?.toLowerCase()
          .includes(searchEmpId.trim().toLowerCase())
      )
    : roleFilteredEmployees;

  /* ---------------- SAFE NAME DISPLAY ---------------- */
  const getEmployeeName = (emp) => {
    const first = emp?.firstName?.trim() || "";
    const last = emp?.lastName?.trim() || "";

    if (first || last) return `${first} ${last}`.trim();
    if (emp?.name) return emp.name;

    return "Unnamed";
  };

  return (
    <div className="employee-page">

      <h2 className="employee-title">Manage Employees</h2>

      {/* ---------------- ACTION BAR ---------------- */}
      <div className="employee-actions">

        {isAdmin() && (
          <input
            type="text"
            placeholder="Search By Employee ID"
            className="search-box"
            value={searchEmpId}
            onChange={(e) => setSearchEmpId(e.target.value)}
          />
        )}

        {isAdmin() && (
          <button
            className="add-btn"
            onClick={() =>
              navigate(`${base}/employee-details/add`)
            }
          >
            Add New Employee
          </button>
        )}

      </div>

      {/* ---------------- NO SEARCH RESULT ---------------- */}
      {isAdmin() &&
        searchEmpId &&
        filteredEmployees.length === 0 && (
          <p className="no-data">
            No employee found with Employee ID "{searchEmpId}"
          </p>
        )}

      {/* ---------------- TABLE ---------------- */}
      <table className="employee-table">

        <thead>
          <tr>
            <th>S No</th>
            <th>Name</th>
            <th>DOB</th>
            <th>Department</th>
            {(isAdmin() || isEmployee()) && <th>Action</th>}
          </tr>
        </thead>

        <tbody>

          {filteredEmployees.length > 0 ? (
            filteredEmployees.map((emp, index) => (
              <tr key={emp.id}>

                <td>{index + 1}</td>
                <td>{getEmployeeName(emp)}</td>
                <td>{emp?.dob || "--"}</td>
                <td>{emp?.department || "--"}</td>

                {/* ---------------- ADMIN ACTIONS ---------------- */}
                {isAdmin() && (
                  <td className="actions">

                    <button
                      className="view"
                      onClick={() =>
                        navigate(`${base}/employee-details/view/${emp.id}`)
                      }
                    >
                      View
                    </button>

                    <button
                      className="edit"
                      onClick={() =>
                        navigate(`${base}/employee-details/edit/${emp.id}`)
                      }
                    >
                      Edit
                    </button>

                    <button
                      className="salary"
                      onClick={() =>
                        navigate(`${base}/employee-details/salary/add/${emp.id}`)
                      }
                    >
                      Salary
                    </button>

                    <button className="delete">
                      Delete
                    </button>

                  </td>
                )}

                {/* ---------------- EMPLOYEE ACTION ---------------- */}
                {isEmployee() && (
                  <td>
                    <button
                      className="salary"
                      onClick={() =>
                        navigate(`${base}/employee-details/leave/apply/${emp.id}`)
                      }
                    >
                      Apply Leave
                    </button>
                  </td>
                )}

              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5" className="no-data">
                No Employees Found
              </td>
            </tr>
          )}

        </tbody>
      </table>

    </div>
  );
}

export default EmployeeDetails;
